import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../hooks/useAuth';

export default function Sidebar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const isStaff = user?.userType === 'user';
  const [logoutHover, setLogoutHover] = useState(false);

  const navItems = [
    { path:'/dashboard',        icon:'◈',  label:'Dashboard',       show:true },
    { path:'/books',            icon:'📚', label:'Books',            show:true },
    { path:'/members',          icon:'👥', label:'Members',          show:isStaff },
    { path:'/requests',         icon:'🔔', label:'Borrow Requests',  show:isStaff },
    { path:'/borrows',          icon:'↔',  label:'Borrows',          show:isStaff },
    { path:'/categories',       icon:'◉',  label:'Categories',       show:true },
    { path:'/create-assistant', icon:'➕', label:'Add Assistant',    show:user?.role==='librarian' },
    { path:'/my-borrows',       icon:'📋', label:'My Library',       show:!isStaff },
  ];

  const roleLabel:any = { librarian:'Librarian', library_assistant:'Library Assistant', student:'Student', staff:'Staff Member' };
  const roleColor:any = { librarian:'#c9a84c', library_assistant:'#10b981', student:'#60a5fa', staff:'#a78bfa' };
  const rc = roleColor[user?.role||''] || '#c9a84c';

  return (
    <>
      <style>{`
        .nav-item { display:flex; align-items:center; gap:11px; padding:11px 14px; border-radius:12px; font-size:14px; font-weight:500; color:rgba(255,255,255,0.45); text-decoration:none; margin-bottom:3px; transition:all .2s; position:relative; overflow:hidden; }
        .nav-item::before { content:''; position:absolute; left:0; top:0; bottom:0; width:3px; background:#c9a84c; border-radius:0 3px 3px 0; transform:scaleY(0); transition:transform .2s; }
        .nav-item:hover { color:rgba(255,255,255,0.85); background:rgba(255,255,255,0.06); }
        .nav-item.active { color:#fff !important; background:linear-gradient(90deg,rgba(201,168,76,0.2),rgba(201,168,76,0.06)) !important; font-weight:700 !important; }
        .nav-item.active::before { transform:scaleY(1); }
        .logout-btn:hover { background:rgba(239,68,68,0.1) !important; color:#f87171 !important; border-color:rgba(239,68,68,0.2) !important; }
      `}</style>

      <aside style={{ width:252, minHeight:'100vh', background:'#080812', borderRight:'1px solid rgba(255,255,255,0.05)', display:'flex', flexDirection:'column', flexShrink:0, position:'relative' }}>

        {/* Gradient accent top */}
        <div style={{ position:'absolute', top:0, left:0, right:0, height:200, background:'radial-gradient(ellipse at top left, rgba(201,168,76,0.08) 0%, transparent 70%)', pointerEvents:'none' }} />
        <div style={{ position:'absolute', bottom:0, left:0, right:0, height:200, background:'radial-gradient(ellipse at bottom left, rgba(99,102,241,0.06) 0%, transparent 70%)', pointerEvents:'none' }} />

        {/* Header */}
        <div style={{ padding:'28px 22px 22px', borderBottom:'1px solid rgba(255,255,255,0.05)', position:'relative' }}>
          <div style={{ marginBottom:2 }}>
            <div style={{ fontFamily:"'Playfair Display',serif", fontSize:20, fontWeight:700, color:'#fff', lineHeight:1.2, letterSpacing:'-0.3px' }}>LibraryMS</div>
            <div style={{ fontSize:10, color:'rgba(201,168,76,0.6)', letterSpacing:'2px', textTransform:'uppercase', marginTop:3 }}>BAUST · University Library</div>
          </div>
          <div style={{ marginTop:14, height:1, background:'linear-gradient(90deg, rgba(201,168,76,0.4), transparent)' }} />
        </div>

        {/* Nav */}
        <nav style={{ flex:1, padding:'18px 12px', overflowY:'auto' }}>
          <div style={{ fontSize:10, fontWeight:700, color:'rgba(255,255,255,0.18)', letterSpacing:'2px', textTransform:'uppercase', padding:'4px 14px', marginBottom:10 }}>
            Menu
          </div>
          {navItems.filter(i=>i.show).map(item=>(
            <NavLink key={item.path} to={item.path}
              className={({isActive})=>`nav-item${isActive?' active':''}`}>
              <span style={{ fontSize:16, width:22, textAlign:'center', flexShrink:0 }}>{item.icon}</span>
              <span>{item.label}</span>
            </NavLink>
          ))}
        </nav>

        {/* User profile */}
        <div style={{ padding:'14px 14px 20px', borderTop:'1px solid rgba(255,255,255,0.05)', position:'relative' }}>
          <div style={{ background:'rgba(255,255,255,0.03)', border:'1px solid rgba(255,255,255,0.06)', borderRadius:14, padding:'14px', marginBottom:10 }}>
            <div style={{ display:'flex', alignItems:'center', gap:12, marginBottom:user?.member_id?10:0 }}>
              {/* Avatar */}
              <div style={{ width:40, height:40, borderRadius:'50%', background:`linear-gradient(135deg, ${rc}cc, ${rc}44)`, border:`2px solid ${rc}44`, display:'flex', alignItems:'center', justifyContent:'center', fontWeight:800, color:'#fff', fontSize:17, flexShrink:0, boxShadow:`0 0 14px ${rc}33` }}>
                {user?.name?.charAt(0).toUpperCase()}
              </div>
              <div style={{ minWidth:0, flex:1 }}>
                <div style={{ fontSize:14, fontWeight:700, color:'#fff', overflow:'hidden', textOverflow:'ellipsis', whiteSpace:'nowrap' }}>{user?.name}</div>
                <div style={{ fontSize:11, color:rc, marginTop:2, fontWeight:600 }}>{roleLabel[user?.role||'']||user?.role}</div>
              </div>
            </div>
            {user?.member_id && (
              <div style={{ display:'flex', alignItems:'center', gap:6, background:'rgba(0,0,0,0.3)', borderRadius:7, padding:'5px 10px' }}>
                <span style={{ fontSize:10, color:'rgba(255,255,255,0.25)', fontWeight:600, letterSpacing:'1px', textTransform:'uppercase' }}>ID</span>
                <span style={{ fontSize:12, color:'rgba(255,255,255,0.5)', fontFamily:'monospace', fontWeight:600 }}>{user.member_id}</span>
              </div>
            )}
          </div>

          <button
            className="logout-btn"
            onMouseEnter={()=>setLogoutHover(true)}
            onMouseLeave={()=>setLogoutHover(false)}
            onClick={()=>{ logout(); navigate('/login'); }}
            style={{ width:'100%', display:'flex', alignItems:'center', justifyContent:'center', gap:8, padding:'10px', borderRadius:11, fontSize:13, fontWeight:600, color:'rgba(255,255,255,0.3)', background:'transparent', border:'1px solid rgba(255,255,255,0.06)', cursor:'pointer', fontFamily:'inherit', transition:'all .2s' }}>
            <span style={{ fontSize:14 }}>⎋</span> Sign Out
          </button>
        </div>
      </aside>
    </>
  );
}
